#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=3005;
ll n,k,dp[N][N],a[N],num[N][N],ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>k;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=n;i++)
	{
		num[i][0]=dp[i][0]=a[i];
	}
	for(int i=1;i<=n;i++)
	{
		ans=max(ans,dp[i][0]);
		for(int j=1;j<i;j++)
		{
			dp[i][j]=num[j][max(0,min(j-1,i-(int)k))]+a[i],
			num[i][j]=max(num[i][j-1],dp[i][j]),
			ans=max(ans,dp[i][j]);
		}
	}
	cout<<ans;
	return 0;
}
